function evaluateLoan(credit, income, debt, emp) {
  const r = [];
  if (credit < 600) r.push("Low credit");
  if (income < 25000) r.push("Low income");
  if (debt > 0.43) r.push("High DTI");
  if (!emp) r.push("Unemployed");
  if (!r.length) return {approved: true, reason: "Approved"};
  return {approved: false, reason: "Denied: " + r.join("; ")};
}
